// SC-03 Tool Simulator with error injection on first sql_query call
const action = $input.item.json.action;

// Check history to detect if sql_query was already attempted
let state;
try {
  const s = $input.item.json.agentState;
  state = typeof s === 'string' ? JSON.parse(s) : (s ?? {});
} catch(e) { state = {}; }
const history = state.history ?? [];
const previousSqlAttempt = history.some(step => step.action === 'sql_query');

const overdueInvoices = [
  {invoice_id: 2001, customer: 'Delta GmbH',   amount_eur: 15000, due_date: '2024-01-15', status: 'overdue'},
  {invoice_id: 2002, customer: 'Epsilon AG',    amount_eur: 8500,  due_date: '2024-02-01', status: 'overdue'},
  {invoice_id: 2003, customer: 'Zeta KG',       amount_eur: 6200,  due_date: '2024-02-10', status: 'overdue'},
  {invoice_id: 2004, customer: 'Eta GmbH',      amount_eur: 4800,  due_date: '2024-02-20', status: 'overdue'},
  {invoice_id: 2005, customer: 'Theta AG',      amount_eur: 3100,  due_date: '2024-03-01', status: 'overdue'}
];

const mockResponses = {
  sql_query: previousSqlAttempt
    ? JSON.stringify({rows: overdueInvoices})                                              // success on retry
    : JSON.stringify({__error: true, message: 'Database connection timeout: host db.internal:5432 unreachable after 30s'}),  // error on first call
  retry_with_fallback: JSON.stringify({rows: overdueInvoices}),
  erp_push: JSON.stringify({status: 'ok', recordsImported: 5})
};

const observation = mockResponses[action] ?? JSON.stringify({error: 'Unknown tool: ' + action});

return [{ json: { ...$input.item.json, observation } }];

const state = $input.item.json;
const finalAnswer = state.finalAnswer ?? '';
const success = finalAnswer.toLowerCase().includes('overdue') || finalAnswer.toLowerCase().includes('invoice');
const history = state.agentState?.history ?? state.history ?? [];
const hadError = history.some(s => {
  try { const obs = JSON.parse(s.observation ?? '{}'); return obs.__error === true; } catch(e) { return false; }
});
const recovered = hadError && success;
console.log('=== SC-03 BENCHMARK RESULT ===');
console.log('Final Answer:', finalAnswer);
console.log('Steps:', state.stepCount);
console.log('Error injected:', hadError);
console.log('Recovered:', recovered);
return [{ json: { finalAnswer, stepCount: state.stepCount, success, errorRecoverySuccess: recovered, reminder: 'Fill in evaluation/results/SC-03_artefact_run001.json' } }];
